var f = this, g = f.grid, w = g.get_element().parentForm, k = f.getItem('ticket').value;
var fileName = get$&Identity;FileName($get('fileupload').value), allowExt = 'xlsx';
var err = (this._language == 'v' ? 'Định dạng tệp không đúng.' : 'Invalid file type.');
if (fileName != '') {
  var ext = fileName.split('.').pop();
  if (allowExt.indexOf(ext.toLowerCase()) < 0) {
    f._checked = false;
    $message.show(err);
  }
  else {
    init$&Identity;IFrame(f);
    var importMemvars = [], unit = (w._action == 'New') ? f._unit : w.getItem('ma_dvcs').value;
    create$&Identity;Memvar(importMemvars, 'ma_dvcs, ma_kho, ma_khon', [unit, w.getItem('ma_kho').value, w.getItem('ma_khon').value]);
    var form = $get('uploadForm'), query = {Language: f._language, Controller: g._controller, Key: k, Memvars: importMemvars, Time: new Date().getTime().toString()};
    $get('query', form).value = Sys.Serialization.JavaScriptSerializer.serialize(query);
    form.action = $func.resolveClientUrl('~/AppHandler/Import.ashx', g._baseUrl);
    form.target = g._controller + '_IFrame';
    form.submit();
    f.request('GetTicket', 'GetTicket', []);
    f._checked = false;
    window.setTimeout(function() {f._busy = true; $func.showWait(f.get_id());}, 50);
  }
}







      &UploadScript;

function init$&Identity;(f) {
  var g = f.grid;
  document.body._form = f;
  $get('fileupload').value = '';
  f.getItem('upload').field.AllowNulls = false;
  $get(f.get_id() + '_form_upload').style.color = 'grey';  
  f.request('GetTicket', 'GetTicket', []);
}
function on$&Identity;$ResponseComplete(f, e) {
  var f = e.object, g = f.grid, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'GetTicket':
      f.setItemValue('ticket', result[0].Value);
      break;
    default:
	  break;
  }
}
function set$Grid$ImportResult(z) {
  var g = z.grid, f = z.form, w = g.get_element().parentForm, result = z.result, row = g._rowCount, first = true, stockIndex = 7, fcAmountIndex = 10, editItemAccountIndex = 25, multiUOMIndex = 24, refIndex = 26;
  var c0 = g._getColumnOrder('ma_vt'), c1 = g._getColumnOrder('dvt'), c2 = g._getColumnOrder('ma_vi_tri'), c3 = g._getColumnOrder('ma_vi_trin'), c4 = g._getColumnOrder('ma_lo');
	var c5 = g._getColumnOrder('ma_nx'), c6 = g._getColumnOrder('tk_du'), c7 = g._getColumnOrder('tk_vt');

  &ImportUserDefinedDeclare;
  var beginUDIndex = 8;

 var fields = 'ma_vt, ten_vt%l, dvt, he_so, ma_vi_tri, ma_vi_trin, ma_lo, ton13, so_luong, px_gia_dd, gia_nt, tien_nt,';
  fields += 'ma_nx, tk_du, tk_vt, ' + '&ImportUserDefinedFields;' + ', gia_ton, lo_yn';
  for (var i = 0; i < result.length; i++) {
    var ins = true, row = g._rowCount, importItems = result[i];
    if (first && row > 0) if (g.blankMemvar(row)) {ins = false; first = false;}
    if (ins) g._appendRow(null, true);
    row = g._rowCount;
    var o = g._getItem(row, c0);
    o.row = row;
    insert$Import$Items(g, fields, row, importItems);

    var ref = importItems[refIndex];
    var itemID = g._getItemValue(row, c0), itemName = g._getItemValue(row, c0 + 1), b0 = (itemName != '' || itemID == '');
    var itemGridBehavior = [
        ['ma_vt', itemID, [itemName, b0], true],
        ['dvt', g._getItemValue(row, c1), ['', ref.substr(0, 1) == '1'], true],
        ['ma_vi_tri', g._getItemValue(row, c2), ['', ref.substr(1, 1) == '1'], true],
        ['ma_vi_trin', g._getItemValue(row, c3), ['', ref.substr(2, 1) == '1'], true],
        ['ma_lo', g._getItemValue(row, c4), ['', ref.substr(3, 1) == '1'], true],
        ['ma_nx', g._getItemValue(row, c5), ['', ref.substr(4, 1) == '1'], true],
        ['tk_du', g._getItemValue(row, c6), ['', ref.substr(5, 1) == '1'], true],
        ['tk_vt', g._getItemValue(row, c7), ['', ref.substr(6, 1) == '1'], true]
    ];
    &ImportUserDefinedSetItem;

    if (importItems[fcAmountIndex] != 0) g.executeExpression(o, [g.$a.gia, g.$a.tien_tg]);
      else g.executeExpression(o, [g.$a.gia, g.$a.tien_nt, g.$a.tien, g.$a.tien_tg]);
    $func.setObjectWhen(g._getItem(row, c1), importItems[multiUOMIndex]);
    $func.setObjectWhen(g._getItem(row, c7), importItems[editItemAccountIndex]);
  }
  on$GridVoucherDetail$RowChange(g, w);
  g._focusWhenTabChanged();
  f._busy = false;
  parent.$func.hideWait(f.get_id());
  f.completion(true);
  z.parentNode.removeChild(z);
}
function insert$Import$Items(g, fields, row, value) {
  var field = fields.split(',');
  for (var i = 0; i < field.length; i++) {
    var column = g._getColumnOrder(parent.$func.trim(field[i]));
    if (column > 0) g._setItemValue(row, column, value[i]);
  }
}







